/**
 * Generates a 2-panel LINE Rich Menu image (2500x843) and re-creates the rich menu.
 *  Left  panel: สั่งสินค้า       -> LIFF ordering page
 *  Right panel: แก้ไขออเดอร์    -> LIFF edit-order page
 *
 * Run: npm run update:rich-menu-image
 */
const sharp = require('sharp');
const path = require('path');
const fs = require('fs');
require('dotenv').config({ path: path.join(__dirname, '..', '.env') });

const ACCESS_TOKEN = process.env.LINE_CHANNEL_ACCESS_TOKEN;
const LIFF_ID = '2009692421-qzL3USNe';

// SVG loaded from file at runtime (generated by write-rich-menu-svg.py)
const SVG_PATH = path.join(__dirname, 'rich-menu.svg');
const svg = fs.readFileSync(SVG_PATH, 'utf8');

const RICH_MENU_BODY = {
  size: { width: 2500, height: 843 },
  selected: true,
  name: 'LINE Ordering Menu v2',
  chatBarText: '\u{1F6D2} \u0E40\u0E21\u0E19\u0E39',
  areas: [
    {
      bounds: { x: 0, y: 0, width: 1250, height: 843 },
      action: { type: 'uri', label: '\u0E2A\u0E31\u0E48\u0E07\u0E2A\u0E34\u0E19\u0E04\u0E49\u0E32', uri: 'https://liff.line.me/' + LIFF_ID },
    },
    {
      bounds: { x: 1250, y: 0, width: 1250, height: 843 },
      action: { type: 'uri', label: '\u0E41\u0E01\u0E49\u0E44\u0E02\u0E2D\u0E2D\u0E40\u0E14\u0E2D\u0E23\u0E4C', uri: 'https://liff.line.me/' + LIFF_ID + '/edit-order' },
    },
  ],
};

async function deleteExistingRichMenus() {
  const res = await fetch('https://api.line.me/v2/bot/richmenu/list', {
    headers: { Authorization: 'Bearer ' + ACCESS_TOKEN },
  });
  const data = await res.json();
  for (const menu of data.richmenus || []) {
    await fetch('https://api.line.me/v2/bot/richmenu/' + menu.richMenuId, {
      method: 'DELETE',
      headers: { Authorization: 'Bearer ' + ACCESS_TOKEN },
    });
    console.log('  deleted: ' + menu.richMenuId);
  }
}

async function createRichMenu() {
  const res = await fetch('https://api.line.me/v2/bot/richmenu', {
    method: 'POST',
    headers: { Authorization: 'Bearer ' + ACCESS_TOKEN, 'Content-Type': 'application/json' },
    body: JSON.stringify(RICH_MENU_BODY),
  });
  const data = await res.json();
  if (!data.richMenuId) throw new Error('Create failed: ' + JSON.stringify(data));
  return data.richMenuId;
}

async function uploadImage(richMenuId, png) {
  const res = await fetch('https://api-data.line.me/v2/bot/richmenu/' + richMenuId + '/content', {
    method: 'POST',
    headers: { Authorization: 'Bearer ' + ACCESS_TOKEN, 'Content-Type': 'image/png' },
    body: png,
  });
  if (!res.ok) throw new Error('Upload failed ' + res.status + ': ' + await res.text());
}

async function setDefaultRichMenu(richMenuId) {
  const res = await fetch('https://api.line.me/v2/bot/user/all/richmenu/' + richMenuId, {
    method: 'POST',
    headers: { Authorization: 'Bearer ' + ACCESS_TOKEN },
  });
  if (!res.ok) throw new Error('Set default failed ' + res.status + ': ' + await res.text());
}

async function main() {
  if (!ACCESS_TOKEN) { console.error('LINE_CHANNEL_ACCESS_TOKEN not set'); process.exit(1); }

  console.log('Generating rich menu image (2-panel)...');
  const png = await sharp(Buffer.from(svg)).png({ compressionLevel: 9 }).toBuffer();
  const outPath = path.join(__dirname, 'rich-menu-preview.png');
  fs.writeFileSync(outPath, png);
  console.log('Image saved: ' + outPath + ' (' + (png.length / 1024).toFixed(0) + ' KB)');

  console.log('Removing existing rich menus...');
  await deleteExistingRichMenus();

  console.log('Creating new 2-area rich menu...');
  const richMenuId = await createRichMenu();
  console.log('Rich Menu ID: ' + richMenuId);

  console.log('Uploading image...');
  await uploadImage(richMenuId, png);

  console.log('Setting as default for all users...');
  await setDefaultRichMenu(richMenuId);

  console.log('Done!');
  console.log('  Left  (order)      : https://liff.line.me/' + LIFF_ID);
  console.log('  Right (edit-order) : https://liff.line.me/' + LIFF_ID + '/edit-order');
}

main().catch((err) => { console.error('ERROR:', err.message); process.exit(1); });
